const body = $json.body || $json;
const contentIdeaId = Number(body.contentIdeaId || 0);
const workflowRunId = Number(body.workflowRunId || 0);
const idempotencyKey = String(body.idempotencyKey || '').trim() || null;
const topic = String(body.topic || '').trim();
const script = String(body.script || '').trim();
const caption = String(body.caption || '').trim();
const keyword = String(body.keyword || topic || '').trim();
const category = String(body.category || '').trim() || null;
const tiktokAccountOpenId = String(body.tiktokAccountOpenId || '').trim() || null;
const source = String(body.source || 'n8n-render-remotion').trim();

const ALLOWED_TEMPLATES = ['tiktok-pro-vertical', 'tiktok-pro-vertical-v1', 'tiktok-bold-story', 'tiktok-clean-minimal'];
const ALLOWED_QUALITIES = ['draft', 'standard', 'high', 'premium'];
const rawTemplateId = String(body.templateId || '').trim();
const rawQualityProfile = String(body.qualityProfile || '').trim();
const templateId = ALLOWED_TEMPLATES.includes(rawTemplateId) ? rawTemplateId : 'tiktok-pro-vertical';
const qualityProfile = ALLOWED_QUALITIES.includes(rawQualityProfile) ? rawQualityProfile : 'premium';

if (!contentIdeaId || contentIdeaId <= 0) throw new Error('contentIdeaId invalide');
if (!workflowRunId || workflowRunId <= 0) throw new Error('workflowRunId invalide');
if (!topic) throw new Error('topic manquant');
if (!script) throw new Error('script manquant');
if (!caption) throw new Error('caption manquante');
if (!keyword) throw new Error('keyword manquant');

const hook = String(body.hook || script.split(/[.!?\n]/)[0] || topic).trim().slice(0, 120);

return [{ json: { contentIdeaId, workflowRunId, idempotencyKey, topic, script, caption, keyword, category, tiktokAccountOpenId, source, hook, templateId, qualityProfile } }];

