const videos = $json.videos || [];
if (!videos.length) throw new Error('Aucune video Pexels trouvee');

const candidates = [];
for (const video of videos) {
  for (const file of video.video_files || []) {
    const width = Number(file.width || video.width || 0);
    const height = Number(file.height || video.height || 0);
    const duration = Number(video.duration || 0);
    const link = String(file.link || '').trim();
    if (!link || height <= width || duration < 5 || duration > 60) continue;

    let score = 0;
    if (width >= 1080 && height >= 1920) score += 150;
    else if (width >= 720 && height >= 1280) score += 100;
    else score += 40;
    if (duration <= 20) score += 120;
    else if (duration <= 35) score += 80;
    else score += 30;
    if (String(file.file_type || '').includes('mp4')) score += 30;

    candidates.push({ link, width, height, duration, score, provider: 'pexels' });
  }
}

if (!candidates.length) throw new Error('Aucune video portrait exploitable');
candidates.sort((a, b) => b.score - a.score);
return [{ json: candidates[0] }];

const input = $('Validate Input').item.json;
const media = $('Select Media').item.json;
const clean = (value, max = 160) => String(value || '').replace(/\s+/g, ' ').trim().slice(0, max);
const durationSec = Math.min(30, Math.max(8, Number(media.duration || 15)));

const renderJob = {
  contractVersion: '1.0.0',
  workflowRunId: Number(input.workflowRunId),
  contentIdeaId: Number(input.contentIdeaId),
  source: input.source || 'n8n-render-remotion',
  requestedAt: new Date().toISOString(),
  idea: {
    category: input.category || null,
    topic: clean(input.topic, 240),
    hook: clean(input.hook || input.topic, 140),
    script: clean(input.script, 4000),
    caption: clean(input.caption, 2200),
    keyword: clean(input.keyword, 240),
    language: 'fr',
    cta: 'Regarde la suite',
    visualStyle: 'premium editorial vertical TikTok'
  },
  account: {
    openId: input.tiktokAccountOpenId || null,
    nickname: null
  },
  render: {
    templateId: input.templateId || 'tiktok-pro-vertical',
    aspectRatio: '9:16',
    width: 1080,
    height: 1920,
    fps: 30,
    durationSec,
    qualityProfile: input.qualityProfile || 'premium',
    captionMode: 'line',
    sceneStrategy: 'single-background',
    safeZones: { topPx: 130, rightPx: 90, bottomPx: 180, leftPx: 90 }
  },
  assets: {
    backgroundVideo: {
      url: media.link,
      provider: media.provider || 'pexels',
      license: null,
      width: Number(media.width || 0) || null,
      height: Number(media.height || 0) || null,
      durationSec: Number(media.duration || 0) || null,
      qualityScore: Number(media.score || 0) || null
    },
    voiceover: null,
    music: null,
    captions: [],
    overlays: [
      { kind: 'title', text: clean(input.hook || input.topic, 120), startMs: 0, endMs: 3500 },
      { kind: 'cta', text: 'Regarde la suite', startMs: Math.max(0, Math.round((durationSec - 4) * 1000)), endMs: Math.round(durationSec * 1000) }
    ]
  },
  publication: {
    title: clean(input.caption || input.topic, 150),
    privacyLevel: null
  }
};

return [{ json: { ...input, renderJob } }];

const baseUrl = String($env.APP_VIDEO_OPS_BACKEND_BASE_URL || '').replace(/\/+$/, '');
const callbackSecret = String($env.APP_VIDEO_OPS_WORKFLOW_CALLBACK_SECRET || '');
const input = $('Build Render Job').item.json;
const render = $('HTTP: RenderVideo Render').item.json;
const idempotencyKey = String(input.idempotencyKey || '').trim();

const body = JSON.stringify({
  status: 'SUCCEEDED',
  message: 'Remotion render completed.',
  responsePayload: JSON.stringify({ contentIdeaId: input.contentIdeaId, renderId: render.renderId, outputUrl: render.outputUrl, engine: 'remotion' })
});

const http = require('http');
const https = require('https');
const { URL } = require('url');
const url = new URL(baseUrl + '/api/video-ops/workflow-runs/' + input.workflowRunId + '/complete');
const client = url.protocol === 'https:' ? https : http;
const response = await new Promise((resolve, reject) => {
  const req = client.request({
    protocol: url.protocol,
    hostname: url.hostname,
    port: url.port || (url.protocol === 'https:' ? 443 : 80),
    path: url.pathname + url.search,
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body),
      'X-Video-Ops-Callback-Secret': callbackSecret,
      ...(idempotencyKey ? { 'X-Idempotency-Key': idempotencyKey } : {}),
      'X-Request-Timestamp': Date.now().toString()
    }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => resolve({ statusCode: res.statusCode || 0, body: data }));
  });
  req.on('error', reject);
  req.setTimeout(20000, () => req.destroy(new Error('Callback timeout')));
  req.write(body);
  req.end();
});

if (response.statusCode < 200 || response.statusCode >= 300) {
  throw new Error('Callback failed: ' + response.statusCode + ' ' + response.body);
}

return [{ json: { ok: true, callbackStatusCode: response.statusCode } }];
